const amqp = require('amqplib');
const crypto = require('crypto');

const RABBITMQ_URL = process.env.RABBITMQ_URL || 'amqp://localhost';
const QUEUE_NAME = 'payment_events';
const HMAC_SECRET = process.env.HMAC_SECRET;
const MAX_AMOUNT = 10000;
const ALLOWED_CURRENCIES = ['USD', 'EUR', 'GBP'];

if (!HMAC_SECRET) {
  throw new Error('HMAC_SECRET environment variable must be set');
}

function verifyMessageSignature(message, signature) {
  const hmac = crypto.createHmac('sha256', HMAC_SECRET);
  hmac.update(message);
  const expectedSignature = hmac.digest('hex');
  return crypto.timingSafeEqual(
    Buffer.from(signature),
    Buffer.from(expectedSignature)
  );
}

function validatePaymentMessage(data) {
  if (!data || typeof data !== 'object') {
    throw new Error('Invalid message format');
  }

  const requiredFields = ['paymentId', 'amount', 'currency', 'userId', 'timestamp'];
  for (const field of requiredFields) {
    if (!data[field]) {
      throw new Error(`Missing required field: ${field}`);
    }
  }

  if (typeof data.amount !== 'number' || data.amount <= 0) {
    throw new Error('Invalid amount');
  }

  if (data.amount > MAX_AMOUNT) {
    throw new Error(`Amount exceeds maximum allowed: ${MAX_AMOUNT}`);
  }

  if (!ALLOWED_CURRENCIES.includes(data.currency)) {
    throw new Error(`Invalid currency: ${data.currency}`);
  }

  if (typeof data.userId !== 'string' || data.userId.length === 0) {
    throw new Error('Invalid userId');
  }

  const messageAge = Date.now() - new Date(data.timestamp).getTime();
  if (messageAge > 300000) {
    throw new Error('Message expired (older than 5 minutes)');
  }

  if (messageAge < -60000) {
    throw new Error('Message timestamp is in the future');
  }

  return true;
}

async function processPayment(paymentData) {
  console.log(`Processing payment: ${paymentData.paymentId}`);
  console.log(`Amount: ${paymentData.amount} ${paymentData.currency}`);
  console.log(`User: ${paymentData.userId}`);
  
  // Simulate payment processing
  await new Promise(resolve => setTimeout(resolve, 100));
  
  console.log(`Payment ${paymentData.paymentId} processed successfully`);
}

async function startConsumer() {
  let connection;
  let channel;

  try {
    connection = await amqp.connect(RABBITMQ_URL);
    channel = await connection.createChannel();

    await channel.assertQueue(QUEUE_NAME, {
      durable: true,
      arguments: {
        'x-max-length': 10000,
        'x-message-ttl': 3600000
      }
    });

    channel.prefetch(1);

    console.log(`Waiting for messages in queue: ${QUEUE_NAME}`);

    channel.consume(QUEUE_NAME, async (msg) => {
      if (msg === null) {
        return;
      }

      try {
        const signature = msg.properties.headers?.signature;
        
        if (!signature) {
          throw new Error('Message signature missing');
        }

        const messageContent = msg.content.toString();
        
        if (!verifyMessageSignature(messageContent, signature)) {
          throw new Error('Message signature verification failed');
        }

        const paymentData = JSON.parse(messageContent);
        
        validatePaymentMessage(paymentData);
        
        await processPayment(paymentData);
        
        channel.ack(msg);
        
      } catch (error) {
        console.error('Error processing message:', error.message);
        
        channel.nack(msg, false, false);
      }
    });

    process.on('SIGINT', async () => {
      console.log('Shutting down consumer...');
      await channel.close();
      await connection.close();
      process.exit(0);
    });

  } catch (error) {
    console.error('Failed to start consumer:', error);
    if (channel) await channel.close();
    if (connection) await connection.close();
    process.exit(1);
  }
}

startConsumer();